var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"무슨 일이야? 나 지금 한참 파티 중이거든?","JPN":"何の用かしら？　今パーティーを楽しんでいる真っ最中なんだけど？","ENG":"What is it? Can't you see I'm enjoying my party?","TWN":"找我幹嘛？我玩得正開心欸！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"지금 한가하게 파티나 즐기고 있을 때가 아닐 텐데?","JPN":"今呑気にパーティーなんか楽しんでいる場合か？","ENG":"I'm not sure if you should be partying at the moment.","TWN":"你現在還有心情玩嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"이 기사들을 한 번 읽어 보시지.","JPN":"こんな記事が何本も出ているぞ。","ENG":"Why don't you read these articles.","TWN":"你看看這些報導！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>연전연승의 카나리아 스쿼드, 관리국 공인 테스크포스에게 승리.</color>","JPN":"<color=#ffd34c>連戦連勝のカナリア・スクワッド、管理局公認のタスクフォースカンパニーに勝利。</color>","ENG":"<color=#ffd34c>Canary Squad: Win After Win. Victory Against Administration's Official TASKFORCE.</color>","TWN":"<color=#ffd34c>屢戰屢勝的金絲雀小隊，從管理局公認的特遣勢力手中奪勝。</color>"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>신데렐라가 될 수 있을 것인가? 떠오르는 신예의 명과 암.</color>","JPN":"<color=#ffd34c>シンデレラとなるか？　浮かび上がる新星の光と闇。</color>","ENG":"<color=#ffd34c>A Cinderella Story? The Light and Shadow of the Rookie.</color>","TWN":"<color=#ffd34c>灰姑娘的故事會上演嗎？明日之星的成與敗。</color>"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>부모님은 죄인이 아니에요! 삼등 시민의 부상, 정치 공작 우려?</color>","JPN":"<color=#ffd34c>両親に罪はありません！　3等市民の負傷、政治工作の疑い？</color>","ENG":"<color=#ffd34c>My Parents Are Not Guilty! Third-Grade Citizen's Uprising and Concerns of Gutter Politics?</color>","TWN":"<color=#ffd34c>我的父母才不是罪犯！三等市民的崛起，是否有政治性操作？</color>"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"으, 다들 정말 재미없게 산다니까~","JPN":"はぁ、みんな本当つまんない生き方するわね～","ENG":"Ugh, these people need to get a life!","TWN":"嗯，大家真的很無聊欸～"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"즐기고 살아도 모자란 인생인데, 저런 삼류 가십에 시간을 낭비하다니 말이야.","JPN":"楽しむだけでも人生は短いというのに、あんな三流ゴシップに時間を無駄にするなんて。","ENG":"Why waste precious time on these tabloid gossips when there isn't even enough time to enjoy life?","TWN":"人生苦短，玩樂的時間都不夠了，竟然還把時間浪費在這種三流八卦新聞上。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서? 저게 나랑 무슨 상관?","JPN":"それで？　この記事と私になんの関係があるの？","ENG":"So? What's this got to do with me?","TWN":"然後呢？這和我有什麼關係？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"무슨 상관이냐고!? 스폰서가 우습나 보지?","JPN":"なんの関係だと！？　スポンサーを何だと思っているんだ？","ENG":"What does it not have to do with you?! Do you think your sponsors are stupid?","TWN":"和你有什麼關係！？你眼裡還有贊助商嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"삼등 시민 놈들이 본선 진출한 것도 어이가 없는데, 멋대로 녀석들 경기를 보러 갔다면서?","JPN":"3等市民どもが本選進出しただけでも呆れるというのに、勝手にそいつらの試合を見に行ったんだってな？","ENG":"It's bad enough that a third-grade citizen made it into the elimination rounds, but you even went to watch their game!","TWN":"三等市民晉級決賽已經夠荒謬了，你竟然還擅自跑去看他們的比賽？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"그것도 가석방된 지 얼마 안 된 와일러까지 대동해서 말이야!","JPN":"しかも仮釈放されて間もないワイラーと一緒にだ！","ENG":"On top of that, you brought Wyler there when his parole has only just been approved?!","TWN":"更誇張的是還帶著才剛保釋的瓦勒一起！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하아, 극적인 연출이란 걸 모르네. 요즘 트렌드 몰라?","JPN":"はぁ、劇的な演出ってやつよ。最近のトレンド、知らないの？","ENG":"*Sigh* You guys know nothing about dramatic setting. Keep up with the trends, will you?","TWN":"哀，你們都不懂什麼叫戲劇效果。你們不知道最近觀眾的喜好嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"마무리가 화기애애한 경기는 대중들에게 금방 잊혀지기 마련이라고.","JPN":"最後馴れ合いで終わるような試合は、民衆からはすぐに忘れられるものよ。","ENG":"Matches with happy endings are forgotten by the end of the day.","TWN":"和樂融融的比賽很快就會被大眾遺忘的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그 애가 피오네한테 물들어서 독기가 빠졌을까 봐 조금 자극해 본 거야.","JPN":"あの子がフィオネたちに毒されて牙が抜けちゃったんじゃないかな、と思って刺激してみただけ。","ENG":"I was worried the kid lost her venom after her fight with Fione. So I wanted to provoke her.","TWN":"我怕她受到菲奧尼的影響，會滅她的威風，所以我才稍微刺激她一下。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"겨우 그런 이유라고?","JPN":"たかだかその程度の理由だと…？","ENG":"That's your reason?","TWN":"就因為這樣？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"우리가 와일러를 꺼내기 위해 얼마나 투자했는지 잊었나?","JPN":"我々がワイラーを刑務所から出すためにどれだけ投資したか忘れたのか？","ENG":"Did you forget how much we spent just to get Wyler out?","TWN":"你忘記我們為了把瓦勒弄出來費了多大力氣嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"엔터테인먼트는 항상 새로운 자극이 필요한 법이지.","JPN":"エンターテインメントには常に新しい刺激が必要なものよ。","ENG":"The entertainment industry is always in need of new stimulus.","TWN":"要有新的刺激才會有娛樂效果嘛。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};